#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor max_pooling_1d_impl_npu(const at::Tensor& self,
                                   int64_t kernel_size,
                                   c10::optional<int64_t> stride_opt,
                                   int64_t padding,
                                   bool return_indices) {
    int64_t stride = stride_opt.has_value() ? stride_opt.value() : kernel_size;
    at::Tensor result = at::empty({self.size(0), self.size(1),
                                   (self.size(-1) + 2 * padding - kernel_size) >= 0
                                     ? ((self.size(-1) + 2 * padding - kernel_size) / stride + 1)
                                     : 0},
                                  self.options());
    EXEC_NPU_CMD(aclnnMaxPooling1dCustom, self, (int)kernel_size, (int)stride, (int)padding, (bool)return_indices, result);
    return result;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("max_pooling_1d_custom", &max_pooling_1d_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("max_pooling_1d_custom", &max_pooling_1d_impl_npu, "MaxPooling1D (MaxPooling1dCustom on NPU)");
}
